SELECT MENU_ID FROM FWK_MENU
WHERE MENU_ID IN

    #{menuId}

SELECT * FROM ( SELECT , ROW_NUMBER() OVER (
ORDER BY
UPPER(m.MENU_ID) UPPER(m.MENU_NAME) UPPER(m.MENU_URL) m.SORT_ORDER, m.MENU_ID
DESC ASC
ORDER BY m.SORT_ORDER, m.MENU_ID
) AS RN
) WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit}

WITH ASSIGNED_MENUS AS ( SELECT MENU_ID FROM (
SELECT #{item} AS MENU_ID FROM DUAL
) ) SELECT DISTINCT m.MENU_ID AS "menuId", m.MENU_NAME AS "menuName", m.MENU_URL AS "menuUrl", m.MENU_IMAGE AS "menuImage", m.SORT_ORDER AS "sortOrder", m.DISPLAY_YN AS "displayYn", m.USE_YN AS "useYn", m.PRIOR_MENU_ID AS "priorMenuId", m.WEB_APP_ID AS "webAppId", m.LAST_UPDATE_DTIME AS "lastUpdateDtime", m.LAST_UPDATE_USER_ID AS "lastUpdateUserId" FROM FWK_MENU m WHERE m.USE_YN = #{useYn} AND m.DISPLAY_YN = #{displayYn} AND ( m.MENU_ID IN (SELECT MENU_ID FROM ASSIGNED_MENUS) OR m.MENU_ID IN ( SELECT DISTINCT PRIOR_MENU_ID FROM FWK_MENU START WITH MENU_ID IN (SELECT MENU_ID FROM ASSIGNED_MENUS) CONNECT BY MENU_ID = PRIOR PRIOR_MENU_ID ) ) ORDER BY m.SORT_ORDER, m.MENU_ID
